import { prisma } from "@/lib/prisma"
import { requireUser } from "@/lib/auth"
import BillingClient from "./BillingClient"
import {
  ACCOUNT_PLAN_OPTIONS,
  getAccountPlanDescription,
  getAccountPlanLabel,
  getPlanUpgradeReason,
  getPlanStatusLabel,
} from "@/lib/platform"

export default async function BillingPage({
  searchParams,
}: {
  searchParams?: { locked?: string }
}) {
  const session = await requireUser()
  const lockedPath = searchParams?.locked || ""

  const [payments, user] = await Promise.all([
    prisma.payment.findMany({
      where: { userId: session.user.id },
      orderBy: { createdAt: "desc" },
      take: 10,
    }),
    prisma.user.findUnique({
      where: { id: session.user.id },
      select: {
        plan: true,
        planStatus: true,
        planActivatedAt: true,
      },
    }),
  ])

  const plans = ACCOUNT_PLAN_OPTIONS.map((plan) => ({
    code: plan.code,
    name: plan.name,
    price: plan.priceLabel,
    description: plan.description,
    perks: [...plan.perks],
    priceId:
      plan.code === "STARTER"
        ? process.env.STRIPE_PRICE_ID_STARTER || process.env.STRIPE_PRICE_ID || null
        : plan.code === "PRO"
          ? process.env.STRIPE_PRICE_ID_PRO || null
          : null,
    highlight: plan.code === "PRO",
  }))

  const lastEvent = payments[0]
  const totalPaid = payments
    .filter((p) => ["paid", "succeeded", "complete"].includes((p.status || "").toLowerCase()))
    .reduce((sum, p) => sum + (p.amount || 0), 0)

  return (
    <div className="min-h-[100svh] bg-[radial-gradient(circle_at_top,rgba(34,211,238,0.12),transparent_24%),linear-gradient(145deg,#020617,#0f172a_55%,#020617)] px-4 py-10 text-white sm:px-6">
      <div className="mx-auto max-w-6xl space-y-8">
        <section className="rounded-[32px] border border-white/10 bg-white/6 p-8 shadow-2xl">
          <div className="flex flex-col gap-6 lg:flex-row lg:items-end lg:justify-between">
            <div className="space-y-3">
              <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">Assinatura</p>
              <h1 className="text-3xl font-semibold md:text-4xl">Seu plano define o alcance da sua conta.</h1>
              <p className="max-w-2xl text-slate-300">
                No Free voce entra com ate 3 caes, blog e racas. Starter e Pro liberam treinos, conteudos, agenda,
                forum social, canais, cursos e o fluxo completo com profissionais.
              </p>
            </div>
            <div className="rounded-2xl border border-emerald-300/20 bg-emerald-500/10 px-5 py-4">
              <p className="text-xs uppercase tracking-[0.2em] text-emerald-100/80">Plano atual</p>
              <p className="mt-2 text-2xl font-semibold">{getAccountPlanLabel(user?.plan)}</p>
              <p className="mt-2 text-sm text-emerald-50/90">{getAccountPlanDescription(user?.plan)}</p>
            </div>
          </div>

          <div className="mt-8 grid gap-4 md:grid-cols-3">
            <Metric
              title="Status"
              value={getPlanStatusLabel(user?.planStatus)}
              description={`Ultimo evento: ${lastEvent ? lastEvent.type : "nenhum"}`}
            />
            <Metric title="Total pago" value={`R$ ${(totalPaid / 100).toFixed(2)}`} description={`${payments.length} eventos financeiros registrados`} />
            <Metric
              title="Ativacao"
              value={
                user?.planActivatedAt
                  ? new Date(user.planActivatedAt).toLocaleDateString("pt-BR", { day: "2-digit", month: "short", year: "numeric" })
                  : "Ainda nao ativado"
              }
              description="Marco do plano atual"
            />
          </div>
        </section>

        {user?.planStatus === "CHECKOUT_REQUIRED" && (
          <div className="rounded-[28px] border border-amber-300/20 bg-amber-500/10 p-5 text-amber-50">
            Sua conta ja foi criada com o plano <strong>{getAccountPlanLabel(user.plan)}</strong>, mas a assinatura
            ainda nao foi concluida. Finalize o checkout para liberar os recursos desse plano.
          </div>
        )}

        {lockedPath && (
          <div className="rounded-[28px] border border-cyan-300/20 bg-cyan-500/10 p-5 text-cyan-50">
            <strong>Upgrade necessario:</strong> {getPlanUpgradeReason(lockedPath)}
          </div>
        )}

        <BillingClient
          plans={plans}
          currentPlan={String(user?.plan || "FREE").toUpperCase()}
          planStatus={String(user?.planStatus || "ACTIVE").toUpperCase()}
        />

      </div>
    </div>
  )
}

function Metric({ title, value, description }: { title: string; value: string; description: string }) {
  return (
    <div className="rounded-2xl border border-white/10 bg-white/5 p-5">
      <p className="text-xs uppercase tracking-[0.2em] text-slate-400">{title}</p>
      <p className="mt-3 text-2xl font-semibold">{value}</p>
      <p className="mt-2 text-sm text-slate-300">{description}</p>
    </div>
  )
}
